```typescript
// dashboard/src/stores/iteration.ts
import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { iterationAPI } from '@/services/iteration.service';
import { ws } from '@/services/websocket';

export const useIterationStore = defineStore('iteration', () => {
  // State
  const iterations = ref<Iteration[]>([]);
  const currentIteration = ref<Iteration | null>(null);
  const loading = ref(false);
  const filters = ref<IterationFilters>({});

  // Computed
  const completedCount = computed(() => 
    iterations.value.filter(i => i.status === 'completed').length
  );

  const successRate = computed(() => {
    const total = completedCount.value + failedCount.value;
    return total > 0 ? (completedCount.value / total * 100).toFixed(1) : '0';
  });

  // Actions
  async function fetchIterations(params?: any) {
    loading.value = true;
    try {
      const data = await iterationAPI.list(params);
      iterations.value = data;
    } finally {
      loading.value = false;
    }
  }

  async function fetchCurrentIteration() {
    const data = await iterationAPI.current();
    currentIteration.value = data;
  }

  // WebSocket 实时更新
  ws.on('iteration.status_changed', (data) => {
    const index = iterations.value.findIndex(i => i.id === data.id);
    if (index !== -1) {
      iterations.value[index] = { ...iterations.value[index], ...data };
    }
  });

  ws.on('iteration.progress', (data) => {
    if (currentIteration.value?.id === data.id) {
      currentIteration.value = { ...currentIteration.value, ...data };
    }
  });

  return {
    iterations,
    currentIteration,
    loading,
    filters,
    completedCount,
    successRate,
    fetchIterations,
    fetchCurrentIteration
  };
});
