// 1. 定义消息schema
interface WebSocketMessage {
  event?: string;
  action?: string;
  channel?: string;
  data?: Record<string, unknown>;
}

// 2. 创建验证器
function validateMessage(data: any): data is WebSocketMessage {
  if (typeof data !== 'object' || data === null) return false;

  const validEvents = ['subscribe', 'unsubscribe', 'control', 'ping', 'pong'];
  if (data.event && !validEvents.includes(data.event)) return false;

  // 限制消息大小
  const jsonSize = JSON.stringify(data).length;
  if (jsonSize > 10240) return false; // 10KB

  return true;
}

// 3. 在处理前验证
connection.socket.on('message', (message) => {
  try {
    const data = JSON.parse(message.toString());

    if (!validateMessage(data)) {
      logger.warn({ data }, 'Invalid WebSocket message');
      connection.socket.send(JSON.stringify({
        event: 'error',
        data: { message: 'Invalid message format' }
      }));
      return;
    }

    handleWebSocketAction(data, connection.socket);
  } catch (error) {
    logger.error(error, 'Failed to parse WebSocket message');
  }
});
```

