// dashboard/src/stores/websocket.ts
import { defineStore } from 'pinia';
import { ref, onUnmounted } from 'vue';

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null);
  const connected = ref(false);
  const messageHandlers = new Map<string, Function[]>();

  function connect() {
    ws.value = new WebSocket('ws://localhost:3000/api/ws');

    ws.value.onopen = () => {
      connected.value = true;
      console.log('✅ WebSocket connected');
    };

    ws.value.onmessage = (event) => {
      const { event: type, data } = JSON.parse(event.data);
      messageHandlers.get(type)?.forEach(handler => handler(data));
    };

    ws.value.onclose = () => {
      connected.value = false;
      setTimeout(connect, 3000); // 重连
    };
  }

  function on(event: string, handler: Function) {
    if (!messageHandlers.has(event)) {
      messageHandlers.set(event, []);
    }
    messageHandlers.get(event)!.push(handler);
  }

  return { connected, connect, on };
});
```

