**修复方案**:

```typescript
// src/config/permissions.ts
export interface PermissionConfig {
  allowedPaths: string[];
  deniedPaths: string[];
  allowNetwork: boolean;
  allowFileWrite: boolean;
  maxFileSize: number;
}

// 默认安全配置
export const DEFAULT_PERMISSIONS: PermissionConfig = {
  allowedPaths: [
    process.cwd(), // 当前项目目录
    '/tmp/ai-dev-team'
  ],
  deniedPaths: [
    '/etc/passwd',
    '/etc/shadow',
    '~/.ssh',
    '~/.gnupg',
    process.env.HOME + '/.config'
  ],
  allowNetwork: true,
  allowFileWrite: true,
  maxFileSize: 100 * 1024 * 1024 // 100MB
};

// src/base-agent.ts
export abstract class BaseAgent {
  private permissionConfig: PermissionConfig;

  constructor(config: AgentConfig, permissions?: Partial<PermissionConfig>) {
    this.permissionConfig = {
      ...DEFAULT_PERMISSIONS,
      ...permissions
    };
  }

  /**
   * 验证文件操作权限
   */
  protected validateFilePath(filePath: string): void {
    const resolvedPath = path.resolve(filePath);

    // 检查是否在拒绝列表中
    for (const denied of this.permissionConfig.deniedPaths) {
      if (resolvedPath.startsWith(denied)) {
        throw new Error(
          `Security: Access denied to protected path: ${filePath}`
        );
      }
    }

    // 检查是否在允许列表中
    const allowed = this.permissionConfig.allowedPaths.some(allowedPath =>
      resolvedPath.startsWith(allowedPath)
    );

    if (!allowed) {
      throw new Error(
        `Security: File path not in allowed list: ${filePath}`
      );
    }
  }

  /**
   * 审计日志
   */
  protected auditLog(action: string, target: string): void {
    const logEntry = {
      timestamp: new Date().toISOString(),
      agent: this.role,
      action,
      target,
      pid: process.pid
    };

    // 写入审计日志
    fs.appendFileSync(
      'audit.log',
      JSON.stringify(logEntry) + '\n'
    );
  }
}
```

