      event: 'error',
      data: { message: 'Authentication required' }
    }));
    connection.socket.close(1008, 'Unauthorized');
    return;
  }

  // 将用户信息附加到 socket
  (connection.socket as any).userId = auth.userId;
  (connection.socket as any).sessionId = auth.sessionId;

  logger.info({
    userId: auth.userId,
    sessionId: auth.sessionId
  }, 'WebSocket client authenticated');

